const send=(t)=>{if(!t.trim())return;const m=[...msgs,{f:"u",t}];setMsgs(m);setChatIn("");setTimeout(()=>{const l=t.toLowerCase();let r="";let ns=chatStep;switch(chatStep){case"init":setChatUserData(p=>({...p,name:t.trim()}));r=`Thanks ${t.trim()}! Could I have a contact number for you please?`;ns="ask_phone";break;case"ask_phone":setChatUserData(p=>({...p,phone:t.trim()}));r="Great, thanks. How can we help you today?\n\n1. Information about our services\n2. A quote or to discuss a project\n3. Work opportunities (joining our team)\n4. Something else";ns="ask_type";break;case"ask_type":if(l.includes("1")||l.includes("service")){r="We offer a full carpentry package for new-build housing — floor joists, roofing, first fix, second fix, and finals/snagging. Which service would you like to know more about? Or I can give you a summary of all.";ns="service_detail";}else if(l.includes("2")||l.includes("quote")||l.includes("project")){r="We'd love to discuss your project. Could you tell me:\n— What type of development?\n— Roughly how many units/plots?\n— Where is the site?";ns="quote_detail";}else if(l.includes("3")||l.includes("work")||l.includes("job")||l.includes("join")){r="Great to hear! We're always looking for skilled carpenters. You can fill in our form on the Work With Us page, or I can arrange a callback. Would you like a callback?";ns="work_detail";}else{r="No problem — could you tell me a bit more about what you need and I'll make sure the right person gets back to you?";ns="general_detail";}break;case"service_detail":if(l.includes("joist"))r="Our floor joist service covers engineered timber, solid timber, trimming around stairwells, strutting and blocking. Shall I arrange a callback to discuss?";else if(l.includes("roof"))r="We do trussed rafter installation, traditional cut roofs, fascia and soffit, roof bracing, and tile battens. Want a callback?";else if(l.includes("first"))r="First fix includes stud partitions, door linings, window boards, noggins, bath panels, and staircase installation. Shall I arrange a callback?";else if(l.includes("second"))r="Second fix — internal doors, skirting, architrave, window trims, built-in wardrobes, loft hatches, staircase finishing. Want a callback?";else if(l.includes("final")||l.includes("snag"))r="Our finals team handles door adjustments, snagging, NHBC pre-inspection checks, and final fitting. Shall I arrange a callback?";else if(l.includes("all")||l.includes("summary"))r="Full package: Floor Joists → Roof Carpentry → First Fix → Second Fix → Finals & Snagging. 21 years' experience. Would you like a callback to discuss?";else r="I can tell you about: floor joists, roofing, first fix, second fix, or finals. Or shall I arrange a callback?";ns="callback_offer";break;case"quote_detail":setChatUserData(p=>({...p,query:t.trim()}));r="Thanks for those details. Would you like us to call you back, or would you prefer an email?";ns="callback_or_email";break;case"work_detail":if(l.includes("yes")||l.includes("call")){r="Perfect — I'll arrange a callback at the number you gave. In the meantime check out the Work With Us page. Anything else I can help with?";ns="anything_else";}else{r="No worries — head to the Work With Us page to fill in an application. Anything else?";ns="anything_else";}break;case"general_detail":setChatUserData(p=>({...p,query:t.trim()}));r="Thanks — I'll pass this on. Would you like a callback or shall we email you?";ns="callback_or_email";break;case"callback_or_email":if(l.includes("call")||l.includes("phone")||l.includes("ring")){r="Great — we'll give you a call ASAP. Anything else I can help with?";}else{r="No problem — we'll email you. Anything else?";}ns="anything_else";break;case"callback_offer":if(l.includes("yes")||l.includes("call")||l.includes("please")){r="Perfect — I'll arrange a callback. Someone from our team will be in touch. Anything else?";ns="anything_else";}else if(l.includes("no")||l.includes("fine")||l.includes("that")){r="No problem at all. Anything else I can help with?";ns="anything_else";}else{r="Would you like me to arrange a callback? Or anything else I can help with?";ns="anything_else";}break;case"anything_else":if(l.includes("no")||l.includes("that")||l.includes("thanks")||l.includes("bye")||l.includes("cheers")){r="Thanks for getting in touch with Miller & Watson Carpentry. Have a great day! 👋";ns="ended";}else{r="Of course — what else can I help with?\n\n1. Our services\n2. A quote or project\n3. Work opportunities\n4. Something else";ns="ask_type";}break;case"ended":r="If you need anything else, feel free to start a new chat or call us directly. Thanks! 😊";break;default:r="How can I help?\n\n1. Our services\n2. A quote or project\n3. Work opportunities\n4. Something else";ns="ask_type";}setChatStep(ns);setMsgs([...m,{f:"b",t:r}]);},600);};
