{pTab==="schedule"&&(<><h3 style={{fontSize:18,fontWeight:700,marginBottom:20}}>This Week</h3><div style={{display:"grid",gap:12}}>{pUser.schedule.map((s,i)=>(<div key={i} style={{background:"#fff",borderRadius:8,padding:20,borderLeft:`4px solid ${s.status==="active"?"#B8860B":s.status==="complete"?"#22c55e":s.status==="delayed"?"#ef4444":"#ddd"}`}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}><div><div style={{fontSize:15,fontWeight:700}}>{s.day} — Plot {s.plot}</div><div style={{fontSize:13,color:"#777",marginTop:2}}>The {s.type} — {s.stage}</div></div><div style={{display:"flex",gap:8,alignItems:"center"}}><span style={{fontSize:11,padding:"4px 12px",borderRadius:100,background:s.status==="active"?"#FFF3E0":s.status==="complete"?"#E8F5E9":s.status==="delayed"?"#FFEBEE":"#f5f5f5",color:s.status==="active"?"#E65100":s.status==="complete"?"#2E7D32":s.status==="delayed"?"#C62828":"#999",fontWeight:600}}>{s.status}</span>{s.status!=="complete"&&s.status!=="delayed"&&<><button onClick={()=>{const u={...pUser};u.schedule=u.schedule.map((x,j)=>j===i?{...x,status:"complete"}:x);setPUser(u);}} style={{...S.bt,background:"#22c55e",color:"#fff",fontSize:11,padding:"6px 14px"}}>Complete</button><button onClick={()=>setDelayModal(i)} style={{...S.bt,background:"#ef4444",color:"#fff",fontSize:11,padding:"6px 14px"}}>{"⏱"} Delayed</button></>}</div></div>{s.status==="delayed"&&s.delayReason&&<div style={{marginTop:10,padding:"8px 12px",background:"#FFF5F5",borderRadius:6,fontSize:12}}><strong style={{color:"#C62828"}}>Delay reason:</strong> {s.delayReason}{s.delayDuration&&<span style={{color:"#999"}}> — Est. {s.delayDuration}</span>}</div>}</div>))}</div>{delayModal!==null&&<div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000,padding:20}}><div style={{background:"#fff",borderRadius:12,padding:28,maxWidth:440,width:"100%"}}><h3 style={{fontSize:16,fontWeight:700,marginBottom:16}}>Report Delay</h3><label style={{fontSize:13,fontWeight:600,display:"block",marginBottom:4}}>Reason for delay *</label><textarea rows={3} placeholder="e.g. Waiting on materials, weather delay..." value={delayReason} onChange={e=>setDelayReason(e.target.value)} style={{width:"100%",border:"1px solid #e0e0e0",borderRadius:6,padding:10,fontSize:13,fontFamily:"inherit",outline:"none",resize:"vertical",marginBottom:12}}/><label style={{fontSize:13,fontWeight:600,display:"block",marginBottom:4}}>Estimated delay duration</label><input placeholder="e.g. 2 days, 1 week..." value={delayDuration} onChange={e=>setDelayDuration(e.target.value)} style={{width:"100%",border:"1px solid #e0e0e0",borderRadius:6,padding:10,fontSize:13,fontFamily:"inherit",outline:"none",marginBottom:16}}/><div style={{display:"flex",gap:8,justifyContent:"flex-end"}}><button onClick={()=>{setDelayModal(null);setDelayReason("");setDelayDuration("");}} style={{...S.bt,background:"#f0f0f0",color:"#333",fontSize:12}}>Cancel</button><button onClick={()=>{if(!delayReason.trim())return;const u={...pUser};u.schedule=u.schedule.map((x,j)=>j===delayModal?{...x,status:"delayed",delayReason:delayReason.trim(),delayDuration:delayDuration.trim()}:x);setPUser(u);setDelayModal(null);setDelayReason("");setDelayDuration("");}} style={{...S.bt,background:"#ef4444",color:"#fff",fontSize:12,opacity:delayReason.trim()?1:0.5}}>Submit Delay</button></div></div></div>}</>)}
